INSERT INTO biomarkers_library (biomarker_name, biomarker_code, category, description, unit_of_measurement, normal_range_male, normal_range_female, clinical_significance, related_conditions, lifestyle_factors, interpretation_guide) VALUES
('ALT (Alanine Aminotransferase)', 'ALT', 'Liver Function', 'ALT is found mainly in liver cells and helps with amino-acid metabolism. When liver cells are damaged, ALT leaks into the bloodstream and the level rises.', 'IU/L', '10–50 IU/L', '10–50 IU/L', 'Raised ALT suggests liver cell irritation or damage. It is one of the main markers used to check for liver disease.', '{"Non-alcoholic fatty liver disease","Alcohol-related liver disease","Viral hepatitis","Drug-induced liver injury"}', '{"Reduce alcohol","Weight management","Review medications","Healthy diet"}', '{"low":"Usually not a concern; may reflect low muscle mass or normal liver health.","high":"Suggests liver cell irritation or damage from fatty liver disease, alcohol, hepatitis or medications.","urgent":"Seek urgent help if you develop jaundice, very dark urine, pale stools, severe abdominal pain or confusion.","improvement":"Reduce or avoid alcohol, lose weight if needed, review medications, and pursue further liver investigations."}'),
('AST (Aspartate Aminotransferase)', 'AST', 'Liver Function', 'AST is present in liver, heart, muscle and other tissues. When these cells are damaged, AST can rise in the blood.', 'IU/L', '10–40 IU/L', '10–40 IU/L', 'High AST may reflect liver conditions, muscle injury or heart problems. It is interpreted together with ALT.', '{"Viral hepatitis","Fatty liver disease","Alcohol-related liver disease","Muscle injury","Heart disease"}', '{"Reduce alcohol","Exercise safely","Healthy diet","Review medications"}', '{"low":"Usually not clinically important and often reflects normal health.","high":"May reflect liver conditions such as hepatitis or fatty liver, muscle injury, or heart problems.","urgent":"Severe abdominal pain, chest pain, jaundice or sudden muscle weakness with dark urine needs urgent assessment.","improvement":"Manage liver disease, avoid alcohol and liver-toxic drugs, address muscle or heart conditions."}'),
('ALP (Alkaline Phosphatase)', 'ALP', 'Liver Function', 'ALP is produced in the liver (bile ducts), bones and other tissues. Raised levels can suggest bile-duct problems, certain liver conditions or active bone turnover.', 'IU/L', 'Varies by age and lab', 'Varies by age and lab; higher in teenagers and pregnancy', 'Raised ALP may indicate bile-duct obstruction, liver disease or bone conditions.', '{"Blocked bile ducts","Primary biliary cholangitis","Bone disease","Healing fractures","Certain cancers"}', '{"Healthy diet","Adequate vitamin D and calcium","Regular check-ups"}', '{"low":"Less common; can be seen in some nutritional deficiencies, thyroid problems or rare genetic conditions.","high":"May occur with blocked bile ducts, cholestasis, bile-duct diseases, bone diseases or healing fractures.","urgent":"Severe abdominal pain, jaundice or very itchy skin with high ALP may need prompt assessment.","improvement":"Treat bile-duct problems, manage liver disease, or address bone conditions under specialist care."}'),
('GGT (Gamma-Glutamyl Transferase)', 'GGT', 'Liver Function', 'GGT is found mainly in the liver and bile ducts. Raised GGT can signal bile-duct obstruction, liver disease or alcohol-related changes.', 'IU/L', 'Varies by lab; often slightly higher in men', 'Varies by lab', 'GGT is commonly used to assess bile-duct health and the effects of alcohol on the liver.', '{"Excess alcohol intake","Fatty liver disease","Chronic hepatitis","Bile-duct obstruction","Cholestasis"}', '{"Reduce or stop alcohol","Weight management","Review medications","Healthy diet"}', '{"low":"Generally not a cause for concern; usually reflects normal liver health.","high":"May occur with excess alcohol, fatty liver disease, chronic hepatitis, bile-duct obstruction or certain medications.","urgent":"Jaundice, severe abdominal pain or confusion with abnormal GGT should prompt urgent medical review.","improvement":"Reduce or stop alcohol, manage weight and metabolic health, review medications, investigate underlying liver or bile-duct disease."}'),
('Total Bilirubin', 'TBIL', 'Liver Function', 'Bilirubin is produced when old red blood cells are broken down and is carried to the liver to be processed and excreted in bile.', 'µmol/L', 'Up to ~20 µmol/L', 'Up to ~20 µmol/L', 'High bilirubin can result from benign conditions like Gilbert syndrome, liver disease, bile-duct obstruction or increased red blood cell breakdown.', '{"Gilbert syndrome","Liver disease","Bile-duct obstruction","Haemolysis"}', '{"Healthy diet","Adequate hydration","Avoid hepatotoxic substances"}', '{"low":"Usually not significant; reflects normal metabolism.","high":"Can result from Gilbert syndrome, liver disease, bile-duct obstruction, or increased red blood cell breakdown (haemolysis).","urgent":"New jaundice, severe abdominal pain or confusion requires urgent assessment.","improvement":"Reassurance for benign Gilbert syndrome; treat liver disease or investigate haemolysis as needed."}'),
('Albumin', 'ALB', 'Liver Function', 'Albumin is the main protein made by the liver. It transports hormones, drugs and other substances and helps keep fluid within blood vessels.', 'g/L', '35–50 g/L', '35–50 g/L', 'Low albumin can indicate advanced liver disease, kidney disease with protein loss, inflammation or poor nutrition.', '{"Advanced liver disease","Kidney disease","Malnutrition","Chronic inflammation"}', '{"Balanced diet","Adequate protein intake","Manage chronic conditions"}', '{"low":"Can occur with advanced liver disease, kidney disease, inflammation, severe illness or poor nutrition. Symptoms may include oedema and fatigue.","high":"Less common; can reflect dehydration.","urgent":"Severe swelling, shortness of breath or sudden weight gain due to fluid retention warrant prompt review.","improvement":"Manage liver or kidney disease, improve nutrition, and address inflammation."}'),
('Total Protein', 'TP', 'Liver Function', 'Total protein reflects the combined concentration of albumin and globulin proteins in the blood.', 'g/L', '60–80 g/L', '60–80 g/L', 'Abnormal levels can point to liver, kidney or immune system issues.', '{"Liver disease","Kidney disease","Malnutrition","Chronic inflammation","Immune disorders"}', '{"Balanced diet","Adequate protein intake","Regular health checks"}', '{"low":"May be seen with liver disease, kidney disease with protein loss, malnutrition or malabsorption.","high":"Can be associated with chronic inflammation, some infections or conditions affecting antibody production.","urgent":"Severe symptoms such as significant swelling, breathlessness or unexplained weight loss warrant medical evaluation.","improvement":"Optimise nutrition, treat liver or kidney disease and investigate immune disorders if suspected."}'),
('CRP (C-Reactive Protein)', 'CRP', 'Inflammation', 'CRP is made by the liver and rises in response to inflammation. It is used to assess infections and inflammatory conditions.', 'mg/L', 'Below ~5–10 mg/L', 'Below ~5–10 mg/L', 'Raised CRP can occur with acute infections, chronic inflammatory diseases, tissue injury, surgery or trauma.', '{"Acute infections","Autoimmune diseases","Chronic inflammatory conditions","Tissue injury"}', '{"Healthy diet","Regular exercise","Stress management","Adequate sleep"}', '{"low":"Very low or undetectable CRP is typical in healthy people.","high":"Can occur with acute infections, chronic inflammatory or autoimmune diseases, tissue injury, surgery or trauma.","urgent":"High CRP with high fever, severe pain, confusion or rapid breathing may indicate serious infection and needs urgent care.","improvement":"Treat the underlying cause; long-term, a healthy lifestyle can help reduce chronic low-grade inflammation."}'),
('ESR (Erythrocyte Sedimentation Rate)', 'ESR', 'Inflammation', 'When inflammation is present, proteins in the blood can cause red cells to clump and settle faster, raising the ESR.', 'mm/hr', 'Varies with age; lower in younger adults', 'Varies with age; lower in younger adults', 'ESR is a non-specific marker of inflammation used alongside symptoms and other tests.', '{"Infections","Autoimmune diseases","Inflammatory diseases","Some cancers","Chronic illnesses"}', '{"Healthy diet","Regular exercise","Manage chronic conditions"}', '{"low":"Usually not a concern; often seen in healthy people.","high":"Can occur with infections, autoimmune or inflammatory diseases, some cancers or chronic illnesses.","urgent":"ESR itself is not an emergency marker; urgent symptoms such as severe pain, high fever or weight loss should prompt immediate medical review.","improvement":"Improvement comes from diagnosing and treating the underlying disease causing inflammation."}'),
('Haemoglobin', 'HB', 'Haematology', 'Haemoglobin carries oxygen from your lungs to tissues and gives blood its red colour. It is a key marker for anaemia.', 'g/L', '130–165 g/L', '115–155 g/L', 'Low haemoglobin indicates anaemia; high haemoglobin may be seen in dehydration, smoking or bone-marrow conditions.', '{"Iron-deficiency anaemia","B12 deficiency","Folate deficiency","Blood loss","Chronic disease","Bone-marrow disorders"}', '{"Iron-rich diet","Adequate B12 and folate","Regular exercise","Stop smoking"}', '{"low":"Indicates anaemia from iron, B12 or folate deficiency, blood loss, chronic disease or bone-marrow problems. Symptoms include tiredness, breathlessness, paleness and dizziness.","high":"May be seen in dehydration, living at high altitude, smoking or certain bone-marrow conditions.","urgent":"Seek urgent help for chest pain, severe breathlessness, black or bloody stools or stroke symptoms.","improvement":"Treat with iron, B12 or folate replacement, address bleeding sources, or manage chronic diseases."}'),
('Haematocrit', 'HCT', 'Haematology', 'Haematocrit measures the proportion of your blood made up of red blood cells, expressed as a percentage or fraction.', 'L/L', '0.40–0.50', '0.36–0.46', 'Helps assess anaemia and polycythaemia.', '{"Anaemia","Polycythaemia","Dehydration","Lung disease","Bone-marrow disorders"}', '{"Adequate hydration","Stop smoking","Treat underlying conditions"}', '{"low":"Usually indicates anaemia and shares causes with low haemoglobin.","high":"May reflect dehydration, lung disease, smoking or bone-marrow conditions that increase red cells.","urgent":"Very high haematocrit with headaches, vision changes or chest pain needs prompt review.","improvement":"Correct anaemia, treat underlying diseases, address dehydration or smoking."}'),
('Red Blood Cell Count', 'RBC', 'Haematology', 'Red blood cells carry oxygen; their number helps evaluate anaemia or polycythaemia.', 'x10¹²/L', '4.5–6.0 x10¹²/L', '4.0–5.5 x10¹²/L', 'Low RBC suggests anaemia; high RBC can result from smoking, altitude, chronic lung disease or bone-marrow disorders.', '{"Anaemia","Polycythaemia","Chronic lung disease","Bone-marrow disorders"}', '{"Iron-rich diet","Stop smoking","Regular exercise","Manage chronic conditions"}', '{"low":"Suggests anaemia from causes similar to low haemoglobin.","high":"Can result from smoking, living at altitude, chronic lung disease or bone-marrow disorders.","urgent":"Sudden or severe symptoms such as chest pain or stroke-like signs with abnormal counts need urgent care.","improvement":"Treat anaemia causes, stop smoking and manage lung or bone-marrow conditions."}'),
('MCV (Mean Corpuscular Volume)', 'MCV', 'Haematology', 'MCV reflects the average size of your red blood cells and helps classify anaemia as microcytic, normocytic or macrocytic.', 'fL', '80–100 fL', '80–100 fL', 'Low MCV often points to iron-deficiency anaemia or thalassaemia; high MCV may be due to B12/folate deficiency, alcohol or liver disease.', '{"Iron-deficiency anaemia","Thalassaemia","B12 deficiency","Folate deficiency","Alcohol excess","Liver disease"}', '{"Balanced diet","Adequate iron, B12 and folate","Moderate alcohol"}', '{"low":"Often points to iron-deficiency anaemia or thalassaemia.","high":"May be due to B12 or folate deficiency, alcohol excess, liver disease or some medications.","urgent":"Marked anaemia with chest pain, breathlessness or neurological symptoms requires urgent assessment.","improvement":"Treat underlying deficiencies, reduce alcohol and manage liver or bone-marrow disease."}'),
('MCH (Mean Corpuscular Haemoglobin)', 'MCH', 'Haematology', 'MCH indicates the average amount of haemoglobin in each red blood cell and helps characterise the type of anaemia.', 'pg', '27–33 pg', '27–33 pg', 'Low MCH is often seen in iron-deficiency anaemia; high MCH commonly accompanies macrocytic anaemia.', '{"Iron-deficiency anaemia","B12 deficiency","Folate deficiency","Inherited red cell conditions"}', '{"Iron-rich diet","Adequate B12 and folate","Moderate alcohol"}', '{"low":"Often seen in iron-deficiency anaemia and some inherited conditions.","high":"Commonly accompanies macrocytic anaemia due to B12 or folate deficiency or alcohol use.","urgent":"Urgency depends on anaemia severity and symptoms.","improvement":"Correct nutrient deficiencies and address alcohol or underlying disease."}'),
('MCHC (Mean Corpuscular Haemoglobin Concentration)', 'MCHC', 'Haematology', 'MCHC measures the concentration of haemoglobin within red blood cells, helping identify whether cells are normally filled with haemoglobin.', 'g/L', '320–360 g/L', '320–360 g/L', 'Low MCHC suggests hypochromic anaemia, often from iron deficiency; high MCHC is less common.', '{"Iron-deficiency anaemia","Inherited red cell disorders"}', '{"Iron-rich diet","Treat underlying conditions"}', '{"low":"Suggests hypochromic anaemia, often from iron deficiency.","high":"Less common; may be seen in certain inherited red cell disorders or sample issues.","urgent":"Urgency is driven by anaemia symptoms rather than MCHC alone.","improvement":"Treat iron deficiency or other red cell disorders."}'),
('Platelet Count', 'PLT', 'Haematology', 'Platelets are small blood cells involved in clotting. Platelet count measures how many platelets are in a given volume of blood.', 'x10⁹/L', '150–400 x10⁹/L', '150–400 x10⁹/L', 'Low platelets can cause bleeding problems; high platelets may occur with inflammation, iron deficiency or bone-marrow disorders.', '{"Viral infections","Autoimmune conditions","Bone-marrow disorders","Iron deficiency","Inflammation"}', '{"Balanced diet","Avoid excessive alcohol","Regular health checks"}', '{"low":"Can result from viral infections, medications, autoimmune conditions or bone-marrow disorders. Symptoms may include easy bruising, nosebleeds or prolonged bleeding.","high":"May occur with inflammation, iron deficiency or bone-marrow disorders.","urgent":"Bleeding that will not stop, blood in vomit or stools, or signs of clot need emergency care.","improvement":"Treat infections, adjust medicines, correct iron deficiency or refer to a haematologist."}'),
('White Blood Cell Count', 'WBC', 'Haematology', 'White blood cells fight infection. WBC count measures immune cells in the blood and helps assess infections and immune disorders.', 'x10⁹/L', '4–11 x10⁹/L', '4–11 x10⁹/L', 'Low WBC can increase infection risk; high WBC often reflects infection, inflammation, stress or some blood cancers.', '{"Infections","Autoimmune disease","Bone-marrow problems","Blood cancers","Medication effects"}', '{"Healthy diet","Regular exercise","Adequate sleep","Hygiene practices"}', '{"low":"Can result from viral infections, medications, autoimmune disease or bone-marrow problems.","high":"Often reflects infection, inflammation, stress or some blood cancers.","urgent":"Fever with very low WBC, or severe infection symptoms, is an emergency.","improvement":"Treat infections, review medications and address bone-marrow or immune disorders."}'),
('Vitamin B12', 'B12', 'Vitamins', 'Vitamin B12 is essential for red blood cell production, nerve function and DNA synthesis. It is obtained from animal-derived foods and some fortified products.', 'pmol/L', 'Varies by lab; low values suggest deficiency', 'Varies by lab; low values suggest deficiency', 'Low B12 can cause anaemia and neurological symptoms; high B12 is usually due to supplementation.', '{"Pernicious anaemia","Vegan diet deficiency","Malabsorption","Gastric conditions"}', '{"Adequate dietary intake","B12 supplementation for vegans","Regular health checks"}', '{"low":"Can result from low intake (vegan diets), pernicious anaemia or malabsorption. Symptoms include tiredness, numbness, tingling and memory problems.","high":"Usually due to supplementation or, rarely, underlying liver or blood conditions.","urgent":"Neurological symptoms such as difficulty walking, severe numbness or confusion need prompt assessment.","improvement":"Oral or injectable B12, dietary changes and investigation for pernicious anaemia or malabsorption."}'),
('Folate (Vitamin B9)', 'FOLATE', 'Vitamins', 'Folate is important for DNA synthesis and red blood cell formation. It comes from leafy greens, beans and fortified foods.', 'µg/L', 'Varies by lab; low values indicate deficiency', 'Varies by lab; low values indicate deficiency', 'Low folate can cause macrocytic anaemia; deficiency in pregnancy requires prompt management.', '{"Macrocytic anaemia","Neural tube defects","Malabsorption","Alcohol excess"}', '{"Green vegetables and pulses","Folic acid supplements","Moderate alcohol","Balanced diet"}', '{"low":"Can cause macrocytic anaemia from poor diet, alcohol excess, malabsorption or increased needs. Symptoms include tiredness and breathlessness.","high":"Usually reflects supplementation.","urgent":"Severe anaemia symptoms need urgent review; folate deficiency in pregnancy requires prompt management.","improvement":"More green vegetables and pulses, folic acid supplements under medical guidance."}'),
('Ferritin', 'FERR', 'Haematology', 'Ferritin is a protein that stores iron inside cells. Blood ferritin approximates body iron stores and is essential in assessing iron deficiency or overload.', 'µg/L', 'Varies by lab; typically higher lower limits in men', 'Varies by lab; typically lower limits in women', 'Low ferritin indicates low iron stores; high ferritin can indicate iron overload, chronic inflammation or liver disease.', '{"Iron-deficiency anaemia","Haemochromatosis","Chronic inflammation","Liver disease"}', '{"Iron-rich diet","Vitamin C to aid absorption","Avoid excess iron supplements","Regular health checks"}', '{"low":"Usually indicates low iron stores and is a sensitive marker for iron deficiency, even before anaemia develops.","high":"Can indicate iron overload, chronic inflammation or liver disease.","urgent":"Severe fatigue, chest pain, black stools or significant weight loss with abnormal ferritin should prompt urgent review.","improvement":"Low ferritin: iron replacement and investigating causes. High ferritin: manage underlying conditions."}');
